VALUES
  ('social-worker-moex-00261', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於社會工作者而言，有關學習人類行為與社會環境之目的，下列組合何者正確？①人類行為受', '["人類經常需要面對生活、心理或社會的需求，且必 須有效的適應", "社會工作者需要一個系統的架構以瞭解各項單獨的知識", "人類天生即具備 因應問題的能力", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00262', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對各理論的批判敘述，何者錯誤？', '["衝突論比較適用於解釋問題，但不利於發展個人處遇策略", "功能論無法解決系統內可能存在的不公平", "符號互動論看個人的自我，是被動採取反應來應對外界帶來的壓力", "生態理論包含範圍廣大，使得理論不容易預測個人行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00263', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據布朗芬布倫納（Bronfenbrenner）的生態系統理論觀點，家長的工作場所屬於什麼系統？', '["微視系統", "中間系統", "外部系統", "鉅視系統"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00264', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關達倫道夫（Dahrendolf）衝突論中對人與社會環境關係的說法，下列組合何者正確？①社會每', '["社會每時每刻都表示出不一致和衝突", "在不違反團體原則與目標時 衝突對社會有正面功能", "社會中的每個要素都對社會變遷發揮作用  ⑤社會以一些人對另些 人的壓迫和強制作基礎", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00265', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關老人與社會的互動，下列敘述何者正確？', '["衝突理論表示，老年人會造成社會重大壓力", "功能理論表示，老年人可以運用充足的社會經歷培養下一代", "符號互動論表示，老人與社會互動會與時俱進，所以不需要特別了解老人文化", "次文化理論表示，老人需要調整自己的價值以配合現在的世代"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00266', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關於家庭暴力相關理論與影響，那些描述正確？①生態理論認為暴力會循環，親密關係暴力會', '["女性主義認為在父權體制的社會意識形態之下，暴力對待女性、兒童與多元 性別的問題將永遠存在", "目睹家庭暴力的兒童成年之後成為親密關係加害者或受害者的風險 較高", "家庭暴力會發生在男性或女性身上，但女性受害風險顯著較高", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00267', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關預立醫療指示（advancedirectives）的說明，下列何者錯誤？', '["最常見的型式是生命意願書或預立遺囑（livingwill）", "不可以指定或是委託代理人，須由個人親自處理", "屬於法律文件，預先做醫療照護的相關決定", "預先表達自己舒適無痛結束生命或者是否延長生命的抉擇"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00268', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '家長為了管教孩子的行為而對於孩子施以懲罰，就相關研究對於懲罰的效果與建議，下列何者最 不適當？', '["家長懲罰孩子同時，建議提出備案來增強其他更適當的行為", "懲罰容易引起負面情緒，對於孩子未來身心發展影響甚鉅", "懲罰可以當下讓孩子注意自我行為，長期為之可持續達到改善行為之效果", "長期對孩子施以懲罰來處理行為可能會造成其攻擊行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00269', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關唐氏症（Downsyndrome）的敘述，下列何者錯誤？', '["為染色體異常導致的疾病", "導因於第23對染色體多一條", "外觀常出現頭圍較小，後腦扁平", "高齡者生出唐氏症孩子的機率較高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00270', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關嬰幼兒受虐的徵候，下列何者錯誤？', '["搖晃嬰兒症候群（shakeninfantsyndrome）", "曼喬森氏症候群（Munchausen’ssyndromebyproxy）", "骨折、燒燙傷", "嬰兒猝死症候群（suddeninfantdeathsyndrome,SIDS）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
